script.text:
      /* <flatten type="Javascript"> */
function init$GridReport$(g) {
  var v = g._ValueFormType, l = (g._language == 'v'), v1 = (v == '10' || v == '40'), v2 =(v == '20' || v == '50'), v3 =(v == '30' || v == '60');
  var list = ['tien', 'tien_nt', 'tien0', 'tien_nt0'], headerColumns = ['', '', (l ? 'đầu năm' : 'opening balance'), (l ? 'đầu năm nt' : 'FC opening balance')];
  g._externalHeaderFields = [], g._$columns = [];

  var header = [
    {Name: 'tien', Header:['cuối năm', 'closing balance'], Value: v1},
    {Name: 'tien', Header:['cuối quý', 'closing balance'], Value: v2},
    {Name: 'tien', Header:['cuối kỳ', 'closing balance'], Value: v3},
    {Name: 'tien_nt', Header:['cuối năm nt', 'FC closing balance'], Value: v1},
    {Name: 'tien_nt', Header:['cuối quý nt', 'FC closing balance'], Value: v2},
    {Name: 'tien_nt', Header:['cuối kỳ nt', 'FC closing balance'], Value: v3}
  ];
  for (var i = 0; i < header.length; i++) {
    if (header[i].Value) {
      var value = (l ? header[i].Header[0] : header[i].Header[1]);
      switch (header[i].Name) {
        case 'tien':
          headerColumns[0] = value;
          break;
        case 'tien_nt':
          headerColumns[1] = value;
          break;
        default:
          break;
      }
    }
  }
  for (var i = 0; i < list.length; i++) { g._$columns.push({Index: g._getColumnOrder(list[i]), Header: headerColumns[i]}); }

  var h1 = [
    {Name: 'tien', Header:['Số cuối năm', 'Closing Balance'], Value: v1},
    {Name: 'tien', Header:['Số cuối quý', 'Closing Balance'], Value: v2},
    {Name: 'tien', Header:['Số cuối kỳ', 'Closing Balance'], Value: v3},
    {Name: 'tien_nt', Header:['Số cuối năm nt', 'FC Closing Balance'], Value: v1},
    {Name: 'tien_nt', Header:['Số cuối quý nt', 'FC Closing Balance'], Value: v2},
    {Name: 'tien_nt', Header:['Số cuối kỳ nt', 'FC Closing Balance'], Value: v3}
  ];

  for (var i = 0; i < h1.length; i++) {
    var index = g._getColumnOrder(h1[i].Name), field = g._fields[index - 1];
    var t = (l ? h1[i].Header[0] : h1[i].Header[1]);
    if (h1[i].Value) {
      if (!field._saveHeaderText) field._saveHeaderText = field.HeaderText;
      else field.HeaderText = field._saveHeaderText;
      field.HeaderText = t;
      Array.add(g._externalHeaderFields, {Index: field.Index, Header: t});
    }
  }
}

function load$GridReport$(g) {g.add_onRender(on$GridReport$Render);}
function dispose$GridReport$(g) {try {g.remove_onRender(on$GridReport$Render);} catch (ex) {}}
function on$GridReport$Render(sender, eventArgs) {
  var g = eventArgs.grid, c1 = g._getColumnOrder('ma_ss'), c2 = g._getColumnOrder('flag');

  if (g._hiddenFields) {
    var a = g._hiddenFields, h = '';
    for (var i = 0; i < a.length; i++) {
      setGridHiddenFields(g, a[i].Fields, a[i].Value);
      if (a[i].Value) h += (h == '' ? '' : ',') + a[i].Fields;
    }
    g._externalHiddenFields = h;
  }

  for (var i = 1; i <= g._rowCount; i++) {
    var flag = g._getItemValue(i, c2), code = g._getItemValue(i, c1);
    if (flag.indexOf('1') != -1) {
      for (var r = 0; r < flag.length; r++) {
        if (flag[r] == 1) {
          var o = g._getItem(i, g._$columns[r].Index), message = '';
          message = (g._language == 'v' ? 'Giá trị hiện tại khác với giá trị ' + g._$columns[r].Header + ' của chỉ tiêu có mã số ' + code : 'This amount is not equal to the ' + g._$columns[r].Header + ' amount of the code ' + code);
          o.className += 'InvalidInput';
          o.title = message;
        }
      }
    }
  }
}

function setGridHiddenFields(g, c, v) {
  var a = c.split(',');
  for (var i = 0; i < a.length; i++) {
    var l = g._getColumnOrder($func.trim(a[i]));
    if (l != -1) g._setColumnVisible(l, !v);
  }
}
/* </flatten> */
